import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.CHSDihme.js";const o="/claude-code-token-free/assets/04_tasktodo_list.DUbNgNHK.png",i="/claude-code-token-free/assets/02_edit_code.DUB5Va3X.png",l="/claude-code-token-free/assets/05_settings.Dh_TXBgx.png",c="/claude-code-token-free/assets/08_scheduled_task.CcRlnu-3.png",n="/claude-code-token-free/assets/07_im.Dm4mM2aa.png",h="/claude-code-token-free/assets/06_settings_computer_use.BFHpyy-L.png",k=JSON.parse('{"title":"功能详解","description":"","frontmatter":{},"headers":[],"relativePath":"desktop/03-features.md","filePath":"desktop/03-features.md","lastUpdated":1780310741000}'),s={name:"desktop/03-features.md"};function p(u,t,b,m,g,q){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h1><blockquote><p>桌面端核心功能模块一览。</p></blockquote><hr><h2 id="聊天引擎" tabindex="-1">聊天引擎 <a class="header-anchor" href="#聊天引擎" aria-label="Permalink to &quot;聊天引擎&quot;">​</a></h2><p><img src="'+o+'" alt="任务列表与工具调用"></p><p>聊天引擎是桌面端核心，负责消息收发、流式渲染和工具交互。</p><h3 id="消息类型" tabindex="-1">消息类型 <a class="header-anchor" href="#消息类型" aria-label="Permalink to &quot;消息类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>组件</th><th>说明</th></tr></thead><tbody><tr><td>用户消息</td><td><code>UserMessage</code></td><td>文本 + 附件画廊</td></tr><tr><td>助手消息</td><td><code>AssistantMessage</code></td><td>Markdown 渲染 + 流式光标 <code>▍</code></td></tr><tr><td>思考块</td><td><code>ThinkingBlock</code></td><td>Extended Thinking，默认折叠</td></tr><tr><td>工具调用</td><td><code>ToolCallBlock</code> / <code>ToolCallGroup</code></td><td>按工具类型专门展示</td></tr><tr><td>工具结果</td><td><code>ToolResultBlock</code></td><td>成功/失败状态 + 输出内容</td></tr><tr><td>权限请求</td><td><code>PermissionDialog</code></td><td>操作预览 + 允许/一直允许/拒绝</td></tr><tr><td>AI 提问</td><td><code>AskUserQuestion</code></td><td>AI 向用户提问的专用输入框</td></tr><tr><td>任务摘要</td><td><code>InlineTaskSummary</code></td><td>后台任务进度内联展示</td></tr></tbody></table><h3 id="工具展示" tabindex="-1">工具展示 <a class="header-anchor" href="#工具展示" aria-label="Permalink to &quot;工具展示&quot;">​</a></h3><p>不同工具有专门的渲染方式：</p><ul><li><strong>Bash</strong> — <code>TerminalChrome</code> 终端风格，深色背景 + <code>$</code> 提示符</li><li><strong>Edit / Write</strong> — <code>DiffViewer</code> 展示文件变更，词级别高亮</li><li><strong>Read</strong> — <code>CodeViewer</code> 语法高亮</li><li><strong>Glob / Grep</strong> — 搜索模式 + 匹配结果</li><li><strong>其他</strong> — JSON 格式展示输入参数</li></ul><h3 id="输入系统" tabindex="-1">输入系统 <a class="header-anchor" href="#输入系统" aria-label="Permalink to &quot;输入系统&quot;">​</a></h3><p><code>ChatInput</code> 组合组件：</p><ul><li>自适应高度文本框（最高 200px）</li><li>附件画廊（粘贴图片 / 拖拽上传 / 文件选择）</li><li>项目上下文芯片（Git 仓库 + 分支）</li><li><code>/</code> 斜杠命令菜单（服务端动态提供，支持搜索）</li><li><code>@</code> 文件搜索菜单（路径自动补全）</li><li>图片画廊（<code>ImageGalleryModal</code> / <code>InlineImageGallery</code>）</li></ul><h3 id="流式输出" tabindex="-1">流式输出 <a class="header-anchor" href="#流式输出" aria-label="Permalink to &quot;流式输出&quot;">​</a></h3><ul><li>Shiki 实时语法高亮</li><li>闪烁光标动画</li><li><code>StreamingIndicator</code> 状态指示</li><li>随时可停止（<code>Cmd/Ctrl + .</code>）</li></ul><hr><h2 id="代码展示" tabindex="-1">代码展示 <a class="header-anchor" href="#代码展示" aria-label="Permalink to &quot;代码展示&quot;">​</a></h2><p><img src="'+i+'" alt="Write 工具 Diff 视图"></p><h3 id="codeviewer" tabindex="-1">CodeViewer <a class="header-anchor" href="#codeviewer" aria-label="Permalink to &quot;CodeViewer&quot;">​</a></h3><p>基于 Shiki（VS Code 同款引擎），支持行号、超 20 行自动折叠、一键复制。</p><h3 id="diffviewer" tabindex="-1">DiffViewer <a class="header-anchor" href="#diffviewer" aria-label="Permalink to &quot;DiffViewer&quot;">​</a></h3><p>基于 react-diff-viewer-continued，单列模式，词级别变更高亮，自动识别文件语言。</p><h3 id="markdownrenderer" tabindex="-1">MarkdownRenderer <a class="header-anchor" href="#markdownrenderer" aria-label="Permalink to &quot;MarkdownRenderer&quot;">​</a></h3><p>基于 marked + DOMPurify，代码块自动 Shiki 高亮，支持表格、列表、引用、链接。</p><h3 id="mermaidrenderer" tabindex="-1">MermaidRenderer <a class="header-anchor" href="#mermaidrenderer" aria-label="Permalink to &quot;MermaidRenderer&quot;">​</a></h3><p>支持流程图、时序图、甘特图等，<code>securityLevel: &#39;strict&#39;</code>，渲染失败回退显示源码。</p><hr><h2 id="多标签系统" tabindex="-1">多标签系统 <a class="header-anchor" href="#多标签系统" aria-label="Permalink to &quot;多标签系统&quot;">​</a></h2><ul><li><code>Cmd/Ctrl + N</code> 新建标签</li><li>拖拽排序、右键菜单（关闭当前/其他/左侧/右侧/全部）</li><li>标签状态：绿色脉冲 = 运行中，红色 = 出错</li><li>关闭运行中标签需确认</li><li>标签状态 localStorage 持久化，重启恢复</li></ul><hr><h2 id="权限控制" tabindex="-1">权限控制 <a class="header-anchor" href="#权限控制" aria-label="Permalink to &quot;权限控制&quot;">​</a></h2><h3 id="四种模式" tabindex="-1">四种模式 <a class="header-anchor" href="#四种模式" aria-label="Permalink to &quot;四种模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>说明</th></tr></thead><tbody><tr><td>询问权限 (default)</td><td>每个操作需确认</td></tr><tr><td>自动接受 (acceptEdits)</td><td>自动允许编辑</td></tr><tr><td>计划模式 (plan)</td><td>只展示计划不执行</td></tr><tr><td>绕过权限 (bypassPermissions)</td><td>全部自动（需二次确认）</td></tr></tbody></table><h3 id="权限请求对话框" tabindex="-1">权限请求对话框 <a class="header-anchor" href="#权限请求对话框" aria-label="Permalink to &quot;权限请求对话框&quot;">​</a></h3><p>显示工具类型、操作预览（Diff/命令内容）、可展开详情。三个按钮：允许 / 一直允许 / 拒绝。</p><hr><h2 id="agent-teams" tabindex="-1">Agent Teams <a class="header-anchor" href="#agent-teams" aria-label="Permalink to &quot;Agent Teams&quot;">​</a></h2><p>当 AI 创建 Agent Team 时，桌面端可视化展示协作状态。</p><ul><li><strong>团队视图</strong> (<code>AgentTeams</code> 页面) — 团队列表 + 成员状态（running/idle/completed/error）</li><li><strong>成员转录</strong> — 点击成员查看完整对话记录（1.5s 轮询更新）</li><li><strong>TeamStatusBar</strong> — 活跃会话底部展示团队名称和成员状态</li></ul><hr><h2 id="提供商管理" tabindex="-1">提供商管理 <a class="header-anchor" href="#提供商管理" aria-label="Permalink to &quot;提供商管理&quot;">​</a></h2><p><img src="'+l+'" alt="提供商设置"></p><p>在设置 → Providers 标签页管理 AI 提供商。</p><h3 id="预设" tabindex="-1">预设 <a class="header-anchor" href="#预设" aria-label="Permalink to &quot;预设&quot;">​</a></h3><p>点击「添加提供商」从预设快速创建：Anthropic、OpenAI、OpenRouter、Ollama、Azure OpenAI、Google AI 等。预设自动填充 Base URL 和 API 格式。</p><h3 id="配置项" tabindex="-1">配置项 <a class="header-anchor" href="#配置项" aria-label="Permalink to &quot;配置项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>API Key</td><td>密钥（密码输入）</td></tr><tr><td>Base URL</td><td>API 地址</td></tr><tr><td>API 格式</td><td><code>anthropic</code> / <code>openai_chat</code> / <code>openai_responses</code></td></tr><tr><td>模型映射</td><td>main / haiku / sonnet / opus 对应的实际模型名</td></tr></tbody></table><h3 id="连接测试" tabindex="-1">连接测试 <a class="header-anchor" href="#连接测试" aria-label="Permalink to &quot;连接测试&quot;">​</a></h3><p>两步验证：连接性 + 模型可用性，结果以 Toast 通知展示。</p><hr><h2 id="技能与-agent" tabindex="-1">技能与 Agent <a class="header-anchor" href="#技能与-agent" aria-label="Permalink to &quot;技能与 Agent&quot;">​</a></h2><h3 id="技能浏览" tabindex="-1">技能浏览 <a class="header-anchor" href="#技能浏览" aria-label="Permalink to &quot;技能浏览&quot;">​</a></h3><p>设置 → Skills 标签页：</p><ul><li>按来源分类（bundled / user / project / plugin）</li><li>搜索过滤</li><li>详情视图：元数据 + 源代码目录树 + 代码内容</li></ul><h3 id="agent-定义" tabindex="-1">Agent 定义 <a class="header-anchor" href="#agent-定义" aria-label="Permalink to &quot;Agent 定义&quot;">​</a></h3><p>设置 → Agents 标签页：</p><p>管理 Agent 类型定义（agentType、description、model、tools、systemPrompt、color），支持 built-in / plugin / userSettings / projectSettings / localSettings 多种来源。</p><hr><h2 id="定时任务" tabindex="-1">定时任务 <a class="header-anchor" href="#定时任务" aria-label="Permalink to &quot;定时任务&quot;">​</a></h2><p><img src="'+c+'" alt="定时任务"></p><p>侧边栏时钟图标进入，顶部统计卡片（总计/活跃/禁用）。</p><h3 id="创建任务" tabindex="-1">创建任务 <a class="header-anchor" href="#创建任务" aria-label="Permalink to &quot;创建任务&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>任务名称</td><td>描述性名称</td></tr><tr><td>提示词</td><td><code>PromptEditor</code> 多行编辑</td></tr><tr><td>Cron 表达式</td><td>标准语法 + <code>cronDescribe</code> 人类可读描述</td></tr><tr><td>星期几</td><td><code>DayOfWeekPicker</code> 可视化多选</td></tr><tr><td>模型</td><td>选择 AI 模型</td></tr><tr><td>权限模式</td><td>执行时的权限策略</td></tr></tbody></table><h3 id="任务管理" tabindex="-1">任务管理 <a class="header-anchor" href="#任务管理" aria-label="Permalink to &quot;任务管理&quot;">​</a></h3><p>启用/禁用开关、运行历史（可展开）、手动运行、删除。</p><hr><h2 id="im-适配器" tabindex="-1">IM 适配器 <a class="header-anchor" href="#im-适配器" aria-label="Permalink to &quot;IM 适配器&quot;">​</a></h2><p><img src="'+n+'" alt="IM 适配器设置"></p><p>设置 → Adapters 标签页，配置 Telegram / 飞书接入。</p><h3 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h3><p><strong>Telegram</strong>: Bot Token + 允许的用户 ID</p><p><strong>飞书</strong>: App ID + App Secret + 加密密钥 + 验证 Token + 允许的用户 open_id + 流式卡片开关</p><h3 id="用户配对" tabindex="-1">用户配对 <a class="header-anchor" href="#用户配对" aria-label="Permalink to &quot;用户配对&quot;">​</a></h3><p>6 位安全码（排除易混淆字符），60 分钟有效，一次性使用。同一用户 5 分钟内最多失败 5 次。</p><h3 id="im-操作" tabindex="-1">IM 操作 <a class="header-anchor" href="#im-操作" aria-label="Permalink to &quot;IM 操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>命令</th><th>效果</th></tr></thead><tbody><tr><td>直接发文本</td><td>与 Claude Code 对话</td></tr><tr><td><code>/new [项目]</code> 或 <code>新会话</code></td><td>开始新会话</td></tr><tr><td><code>/projects</code> 或 <code>项目列表</code></td><td>查看最近项目</td></tr><tr><td><code>/stop</code> 或 <code>停止</code></td><td>停止生成</td></tr></tbody></table><p>权限请求在 IM 中以按钮形式展示（Telegram Inline Keyboard / 飞书 Interactive Card）。</p><hr><h2 id="computer-use" tabindex="-1">Computer Use <a class="header-anchor" href="#computer-use" aria-label="Permalink to &quot;Computer Use&quot;">​</a></h2><p><img src="'+h+'" alt="Computer Use 设置"></p><p>设置 → Computer Use 标签页，查看和配置 Computer Use 功能状态。</p><p><code>ComputerUseSettings</code> 页面展示：平台信息、Python 环境、venv 状态、依赖安装情况、权限配置。</p><hr><h2 id="工具检查" tabindex="-1">工具检查 <a class="header-anchor" href="#工具检查" aria-label="Permalink to &quot;工具检查&quot;">​</a></h2><p><code>ToolInspection</code> 页面，查看当前会话中可用的工具列表和详情。</p><hr><h2 id="设计系统" tabindex="-1">设计系统 <a class="header-anchor" href="#设计系统" aria-label="Permalink to &quot;设计系统&quot;">​</a></h2><h3 id="颜色" tabindex="-1">颜色 <a class="header-anchor" href="#颜色" aria-label="Permalink to &quot;颜色&quot;">​</a></h3><p>暖色调设计语言：</p><ul><li><strong>品牌色</strong>: <code>#8F482F</code>（褐红色）</li><li><strong>浅色背景</strong>: <code>#FAF9F5</code>（奶油色）</li><li><strong>信息色</strong>: <code>#2D628F</code> / <strong>成功色</strong>: <code>#4F6237</code> / <strong>错误色</strong>: <code>#BA1A1A</code></li></ul><h3 id="主题" tabindex="-1">主题 <a class="header-anchor" href="#主题" aria-label="Permalink to &quot;主题&quot;">​</a></h3><p>浅色/深色切换，设置 → 通用中配置。</p><h3 id="动画" tabindex="-1">动画 <a class="header-anchor" href="#动画" aria-label="Permalink to &quot;动画&quot;">​</a></h3><table tabindex="0"><thead><tr><th>名称</th><th>用途</th></tr></thead><tbody><tr><td><code>shimmer</code></td><td>流式输出闪烁光标</td></tr><tr><td><code>pulse-dot</code></td><td>运行中会话指示</td></tr><tr><td><code>spin</code></td><td>加载旋转</td></tr><tr><td><code>progress-fill</code></td><td>进度条填充</td></tr></tbody></table><h3 id="toast-通知" tabindex="-1">Toast 通知 <a class="header-anchor" href="#toast-通知" aria-label="Permalink to &quot;Toast 通知&quot;">​</a></h3><p>右下角固定通知，四种类型（success/error/warning/info），自动消失 + 手动关闭。</p><h3 id="自动更新" tabindex="-1">自动更新 <a class="header-anchor" href="#自动更新" aria-label="Permalink to &quot;自动更新&quot;">​</a></h3><p><code>UpdateChecker</code> 组件：启动后检查 GitHub Releases，有新版本时弹出更新提示，支持自动下载安装重启。</p><hr><h2 id="国际化" tabindex="-1">国际化 <a class="header-anchor" href="#国际化" aria-label="Permalink to &quot;国际化&quot;">​</a></h2><p>支持中文 (<code>zh</code>) 和英文 (<code>en</code>)，设置 → 通用中切换，<code>localStorage</code> 持久化。</p><p>Key 命名空间：<code>common.*</code>、<code>sidebar.*</code>、<code>chat.*</code>、<code>settings.*</code>、<code>status.*</code>、<code>titlebar.*</code> 等。</p><hr><h2 id="键盘快捷键" tabindex="-1">键盘快捷键 <a class="header-anchor" href="#键盘快捷键" aria-label="Permalink to &quot;键盘快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Cmd/Ctrl + N</code></td><td>新建会话</td></tr><tr><td><code>Cmd/Ctrl + K</code></td><td>聚焦搜索</td></tr><tr><td><code>Cmd/Ctrl + .</code></td><td>停止生成</td></tr><tr><td><code>Escape</code></td><td>关闭模态框</td></tr><tr><td><code>Enter</code></td><td>发送消息</td></tr><tr><td><code>Shift + Enter</code></td><td>换行</td></tr><tr><td><code>/</code></td><td>斜杠命令</td></tr><tr><td><code>@</code></td><td>文件搜索</td></tr></tbody></table>',106)])])}const P=e(s,[["render",p]]);export{k as __pageData,P as default};
